import React, { useState, useEffect } from "react";
import ab1 from "../assets/ab-hl-1.jpg";
import ab2 from "../assets/ab-hl-2.jpeg";
import ab3 from "../assets/ab-hl-3.jpg";
import ab4 from "../assets/ab-hl-4.jpg";

function About() {
  const images = [ab1, ab2, ab3, ab4];
  const [currentIndex, setCurrentIndex] = useState(0);

  // ===== page hit counter =====
  const [hits, setHits] = useState(0);
  const [displayHits, setDisplayHits] = useState(0);

  // slideshow
  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % images.length);
    }, 4000);
    return () => clearInterval(interval);
  }, []);

  // hit counter logic
  useEffect(() => {
    let count = Number(localStorage.getItem("aboutPageHits") || 0);
    count += 1;
    localStorage.setItem("aboutPageHits", count);
    setHits(count);
  }, []);

  // animate counter
  useEffect(() => {
    let start = 0;
    const duration = 1200;
    const startTime = performance.now();

    const animate = (time) => {
      const progress = Math.min((time - startTime) / duration, 1);
      setDisplayHits(Math.floor(progress * hits));
      if (progress < 1) requestAnimationFrame(animate);
    };

    requestAnimationFrame(animate);
  }, [hits]);

  return (
    <section
      id="about-section"
      style={{
        position: "relative",
        height: "480px",
        display: "flex",
        alignItems: "flex-end",
        justifyContent: "center",
        margin: "60px auto",
        borderRadius: "15px",
        overflow: "hidden",
        maxWidth: "1100px",
        boxShadow: "0 8px 20px rgba(0,0,0,0.2)",
      }}
    >
      {/* Background Slideshow */}
      <img
        src={images[currentIndex]}
        alt="About Slide"
        style={{
          position: "absolute",
          width: "100%",
          height: "100%",
          objectFit: "cover",
          top: 0,
          left: 0,
          transition: "opacity 1s ease-in-out",
          zIndex: -1,
        }}
      />

      {/* Info Box */}
      <div
        style={{
          width: "100%",
          padding: "25px 30px 30px",
          backgroundColor: "rgba(255, 255, 255, 0.88)",
          textAlign: "center",
          backdropFilter: "blur(6px)",
        }}
      >
        <h2
          style={{
            marginBottom: "12px",
            fontSize: "26px",
            fontWeight: "700",
            color: "#007bff",
          }}
        >
          HEALink
        </h2>

        <p
          style={{
            fontSize: "16px",
            color: "#333",
            lineHeight: "1.6",
            maxWidth: "900px",
            margin: "0 auto 20px",
          }}
        >
          HEALink was started with a vision to connect people with better
          healthcare solutions. We provide pathology, medicine, consultancy, and
          blood bank services to make healthcare accessible and reliable for
          everyone. Our mission is to ensure that every individual gets the care
          they need with trust and convenience.
        </p>

        {/* ===== Page Hit Counter ===== */}
        <div
          style={{
            marginTop: "10px",
            paddingTop: "14px",
            borderTop: "1px solid rgba(0,0,0,0.1)",
          }}
        >
          <div
            style={{
              fontSize: "14px",
              color: "#666",
              letterSpacing: "0.5px",
            }}
          >
            👀 Page Views
          </div>

          <div
            style={{
              fontSize: "28px",
              fontWeight: "700",
              color: "#0e3b5f",
              marginTop: "4px",
              transition: "transform 0.3s ease",
            }}
          >
            {displayHits.toLocaleString()}
          </div>
        </div>
      </div>
    </section>
  );
}

export default About;
